        #     # (Think of `Ts` as a tuple of an arbitrary number of individual
        #     #  `TypeVar`s, which the `Unpack` is 'pulling out' directly into the
        #     #  `Generic[]`.)
        #     class Bar(Generic[Unpack[Ts]]): ...
        #     Bar[int]  # Valid
        #     Bar[int, str]  # Also valid
        # 
